load('exp2_lab2.mat')

% Voltage across Diode-Connected Transistor vs Input Voltage (all three)
figure(); %[output:6c59a2c6]
semilogy(V_in_120, V_q_120, '.', DisplayName='120 \Omega') %[output:6c59a2c6]
hold on; %[output:6c59a2c6]
semilogy(V_in_10k, V_q_10k, '.', DisplayName='10 k\Omega') %[output:6c59a2c6]
semilogy(V_in_200k, V_q_200k, '.', DisplayName='200 k\Omega') %[output:6c59a2c6]
title('Voltage Across Transistor vs. Input Voltage') %[output:6c59a2c6]
xlabel('V_{in} (V)') %[output:6c59a2c6]
ylabel('V_{Q} (V)') %[output:6c59a2c6]
legend(Location="best") %[output:6c59a2c6]

% Current Flowing into Circuit vs. Input Voltage
figure(); %[output:6149e5c7]
semilogy(V_in_120, I_in_120, '.', DisplayName='120 \Omega') %[output:6149e5c7]
hold on; %[output:6149e5c7]
semilogy(V_in_10k, I_in_10k, '.', DisplayName='10 k\Omega') %[output:6149e5c7]
semilogy(V_in_200k, I_in_200k, '.', DisplayName='200 k\Omega') %[output:6149e5c7]

fit_vals = polyfit(V_in_120(find(V_in_120>1)), I_in_120(find(V_in_120>1)), 1);
semilogy(linspace(0, 3, 101), fit_vals(1) .* linspace(0, 3, 101) + fit_vals(2), DisplayName='Effect of Resistor Fitted Line, R = 120 \Omega') %[output:6149e5c7]
fit_vals = polyfit(V_in_10k(find(V_in_10k>1)), I_in_10k(find(V_in_10k>1)), 1);
semilogy(linspace(0, 3, 101), fit_vals(1) .* linspace(0, 3, 101) + fit_vals(2), DisplayName='Effect of Resistor Fitted Line, R = 10 k\Omega') %[output:6149e5c7]
fit_vals = polyfit(V_in_200k(find(V_in_200k>0.8)), I_in_200k(find(V_in_200k>0.8)), 1);
semilogy(linspace(0, 3, 101), fit_vals(1) .* linspace(0, 3, 101) + fit_vals(2), DisplayName='Effect of Resistor Fitted Line, R = 200 k\Omega') %[output:6149e5c7]

title('Current vs. Input Voltage of Circuit') %[output:6149e5c7]
xlabel('V_{in} (V)') %[output:6149e5c7]
ylabel('I_{in} (A)') %[output:6149e5c7]
legend(Location="best") %[output:6149e5c7]

% Plot showing input current vs applied input voltage (3 plots)
U_T = 25e-3; % V
I_s = 3e-15; % A

figure(); %[output:6129e7d9]
hold on; %[output:6129e7d9]
plot(V_in_120, I_in_120, '.', DisplayName='Measured Data') %[output:6129e7d9]
plot(log(((U_T/120)/I_s) + 1) * U_T, U_T/120, 'x', DisplayName='(V_{on}, I_{on}) with U_{T} = 25 mV; I_{s} = 3 fA') %[output:6129e7d9]
title('Circuit with 120 \Omega Resistor IV Plot') %[output:6129e7d9]
xlabel('V_{in} (V)') %[output:6129e7d9]
ylabel('I_{in} (A)') %[output:6129e7d9]
legend(Location='southeast') %[output:6129e7d9]

figure(); %[output:1758ff90]
hold on; %[output:1758ff90]
plot(V_in_10k, I_in_10k, '.', DisplayName='Measured Data') %[output:1758ff90]
plot(log(((U_T/10e3)/I_s) + 1) * U_T, U_T/10e3, 'x', DisplayName='(V_{on}, I_{on}) with U_{T} = 25 mV; I_{s} = 3 fA') %[output:1758ff90]
title('Circuit with 10 k\Omega Resistor IV Plot') %[output:1758ff90]
xlabel('V_{in} (V)') %[output:1758ff90]
ylabel('I_{in} (A)') %[output:1758ff90]
legend(Location='southeast') %[output:1758ff90]

figure(); %[output:409d25eb]
hold on; %[output:409d25eb]
plot(V_in_200k, I_in_200k, '.') %[output:409d25eb]
plot(log(((U_T/200e3)/I_s) + 1) * U_T, U_T/200e3, 'x', DisplayName='(V_{on}, I_{on}) with U_{T} = 25 mV; I_{s} = 3 fA') %[output:409d25eb]
title('Circuit with 200 k\Omega Resistor IV Plot') %[output:409d25eb]
xlabel('V_{in} (V)') %[output:409d25eb]
ylabel('I_{in} (A)') %[output:409d25eb]
legend(Location='southeast') %[output:409d25eb]

% I_on vs V_on
figure(); %[output:2678e36b]
hold on; %[output:2678e36b]
plot(log(((U_T/120)/I_s) + 1) * U_T, U_T/120, 'x', DisplayName='(V_{on}, I_{on}) with U_{T} = 25 mV; I_{s} = 3 fA; R = 120 \Omega') %[output:2678e36b]
plot(log(((U_T/10e3)/I_s) + 1) * U_T, U_T/10e3, 'x', DisplayName='(V_{on}, I_{on}) with U_{T} = 25 mV; I_{s} = 3 fA; R = 10 k\Omega') %[output:2678e36b]
plot(log(((U_T/200e3)/I_s) + 1) * U_T, U_T/200e3, 'x', DisplayName='(V_{on}, I_{on}) with U_{T} = 25 mV; I_{s} = 3 fA; R = 200 k\Omega') %[output:2678e36b]
xlabel('V_{on} (V)') %[output:2678e36b]
ylabel('I_{on} (A)') %[output:2678e36b]
legend(Location='best') %[output:2678e36b]

% V_on and I_on as a function of R w/ Data
R_vals = linspace(0, 1e6, 1e6);

figure(); %[output:73db3b6f]
yyaxis left %[output:73db3b6f]
semilogx(R_vals, log(((U_T./R_vals)/I_s) + 1) .* U_T) %[output:73db3b6f]
hold on; %[output:73db3b6f]
xlabel('Resistance in Series (R)') %[output:73db3b6f]
ylabel('V_{on} (V)') %[output:73db3b6f]
yyaxis right %[output:73db3b6f]
semilogx(R_vals, U_T ./ R_vals) %[output:73db3b6f]
ylabel('I_{on} (A)') %[output:73db3b6f]

yyaxis left %[output:73db3b6f]
semilogx(120, log(((U_T/120)/I_s) + 1) * U_T, 'x') %[output:73db3b6f]
semilogx(10e3, log(((U_T/10e3)/I_s) + 1) * U_T, 'x') %[output:73db3b6f]
semilogx(200e3, log(((U_T/200e3)/I_s) + 1) * U_T, 'x') %[output:73db3b6f]
yyaxis right %[output:73db3b6f]
semilogx(120, U_T/120, 'x') %[output:73db3b6f]
semilogx(10e3, U_T/10e3, 'x') %[output:73db3b6f]
semilogx(200e3, U_T/200e3, 'x') %[output:73db3b6f]

% V_on and I_on as a function of R w/0=o Theoretical
figure(); %[output:689ab18a]
yyaxis left %[output:689ab18a]
semilogx(120, log(((U_T/120)/I_s) + 1) * U_T, 'x') %[output:689ab18a]
hold on; %[output:689ab18a]
semilogx(10e3, log(((U_T/10e3)/I_s) + 1) * U_T, 'x') %[output:689ab18a]
semilogx(200e3, log(((U_T/200e3)/I_s) + 1) * U_T, 'x') %[output:689ab18a]
yyaxis right %[output:689ab18a]
semilogx(120, U_T/120, 'x') %[output:689ab18a]
semilogx(10e3, U_T/10e3, 'x') %[output:689ab18a]
semilogx(200e3, U_T/200e3, 'x') %[output:689ab18a] %[output:6e9bc00b] %[output:7cc4502c]

